CREATE TABLE workshop_sequences(tenant_id uuid NOT NULL REFERENCES tenants(id),organization_id uuid NOT NULL REFERENCES organizations(id),year integer NOT NULL,value integer NOT NULL,PRIMARY KEY(tenant_id,organization_id,year));
CREATE TABLE work_orders(id uuid PRIMARY KEY,tenant_id uuid NOT NULL REFERENCES tenants(id),organization_id uuid NOT NULL REFERENCES organizations(id),site_id uuid NOT NULL REFERENCES sites(id),customer_id uuid NOT NULL REFERENCES customers(id),asset_id uuid NOT NULL REFERENCES assets(id),booking_id uuid REFERENCES bookings(id),quote_id uuid REFERENCES quotes(id),number text NOT NULL,check_in jsonb NOT NULL,jobs jsonb NOT NULL DEFAULT '[]'::jsonb,status text NOT NULL,quality_approved_by uuid,quality_notes text,created_by uuid NOT NULL,created_at timestamptz NOT NULL,updated_at timestamptz NOT NULL,released_at timestamptz,UNIQUE(tenant_id,organization_id,number));
CREATE INDEX work_orders_board_idx ON work_orders(tenant_id,site_id,status,updated_at);
DO $$ DECLARE n text;BEGIN FOREACH n IN ARRAY ARRAY['workshop_sequences','work_orders'] LOOP EXECUTE format('ALTER TABLE %I ENABLE ROW LEVEL SECURITY',n);EXECUTE format('ALTER TABLE %I FORCE ROW LEVEL SECURITY',n);EXECUTE format('CREATE POLICY tenant_isolation ON %I USING (tenant_id=current_setting(''app.tenant_id'',true)::uuid) WITH CHECK (tenant_id=current_setting(''app.tenant_id'',true)::uuid)',n);END LOOP;END $$;
